insert into lessons (slug, title, summary, chapter_id, subchapter_id, sort_order, status, is_free_preview)
select v.slug, v.title, v.summary, c.id, sc.id, v.sort_order, 'draft', false from (values
('seconde-svt-1-s1-l1', 'Le matériel de la sortie écologique', 'Utiliser sur le terrain le matériel adapté (loupe, flacon, pince, boussole, filet) pour étudier les êtres vivants d''un milieu.', 'seconde-svt-1', 'seconde-svt-1-s1', 1),
('seconde-svt-1-s1-l2', 'Identifier les êtres vivants dans leur milieu', 'Repérer animaux et végétaux dans leurs milieux habituels (sol, sous-sol, eau, air) : insectes, vers, graminées, plantes aquatiques.', 'seconde-svt-1', 'seconde-svt-1-s1', 2),
('seconde-svt-1-s1-l3', 'Les notions clés de l''écologie', 'Définir écologie, biotope, biocénose, écosystème, biomasse et environnement à partir des relations entre êtres vivants.', 'seconde-svt-1', 'seconde-svt-1-s1', 3),
('seconde-svt-1-s1-l4', 'Les zones écofloristiques du Togo', 'Localiser les principales zones abritant les écosystèmes au Togo : mangrove, savane, forêt et milieux aquatiques.', 'seconde-svt-1', 'seconde-svt-1-s1', 4),
('seconde-svt-1-s1-l5', 'Relations entre êtres vivants et effets de nombre', 'Distinguer relations intraspécifiques et interspécifiques, puis caractériser l''effet de groupe et l''effet de masse.', 'seconde-svt-1', 'seconde-svt-1-s1', 5),
('seconde-svt-1-s1-l6', 'Chaînes alimentaires et interdépendance', 'Construire chaîne et réseau trophiques, expliquer transferts d''énergie et l''interdépendance en lutte biologique et fertilisation des sols.', 'seconde-svt-1', 'seconde-svt-1-s1', 6),
('seconde-svt-1-s2-l1', 'Effet de serre et réchauffement de la planète', 'Expliquer le mécanisme de l''effet de serre et les activités humaines à l''origine du réchauffement de la planète.', 'seconde-svt-1', 'seconde-svt-1-s2', 7),
('seconde-svt-1-s2-l2', 'Les grands problèmes environnementaux', 'Identifier pollution des eaux, érosion côtière, déforestation, dégradation des sols, pesticides, pêche anarchique, braconnage et feux de brousse.', 'seconde-svt-1', 'seconde-svt-1-s2', 8),
('seconde-svt-1-s2-l3', 'Conséquences sur le développement durable', 'Déduire les conséquences des changements climatiques, de la perte de biodiversité et des pollutions sur le développement durable.', 'seconde-svt-1', 'seconde-svt-1-s2', 9),
('seconde-svt-1-s2-l4', 'Les mesures de protection de l''environnement', 'Proposer reboisement, pare-feux, agroforesterie, recyclage et gestion rationnelle des ressources naturelles.', 'seconde-svt-1', 'seconde-svt-1-s2', 10),
('seconde-svt-1-s2-l5', 'Produire des affiches de sensibilisation', 'Réaliser des affiches pour sensibiliser ses pairs au maintien de l''équilibre de la nature et aux comportements responsables.', 'seconde-svt-1', 'seconde-svt-1-s2', 11),
('seconde-svt-2-s1-l1', 'Développement d''une plante verte', 'Décrire les étapes de la germination (hétérotrophie) puis de la croissance (autotrophie) d''une plante verte.', 'seconde-svt-2', 'seconde-svt-2-s1', 1),
('seconde-svt-2-s1-l2', 'Le rôle des sels minéraux', 'Déterminer le rôle des sels minéraux azote, phosphore et potassium (N, P, K) et la notion de concentration optimale.', 'seconde-svt-2', 'seconde-svt-2-s1', 2),
('seconde-svt-2-s1-l3', 'Applications de la nutrition minérale', 'Déduire les usages pratiques : préparation d''engrais, culture sous serre, culture sans sol et aquaculture.', 'seconde-svt-2', 'seconde-svt-2-s1', 3),
('seconde-svt-2-s1-l4', 'Réaliser des cultures de légumes', 'Aménager cultures et jardins potagers (tomates, haricot vert, fleurs) à l''école ou à la maison.', 'seconde-svt-2', 'seconde-svt-2-s1', 4),
('seconde-svt-2-s2-l1', 'Les échanges gazeux chlorophylliens', 'Mettre en évidence les échanges gazeux chlorophylliens d''une plante verte à la lumière et à l''obscurité.', 'seconde-svt-2', 'seconde-svt-2-s2', 5),
('seconde-svt-2-s2-l2', 'Intensité et quotient d''assimilation', 'Calculer l''intensité d''assimilation chlorophyllienne et le quotient d''assimilation chlorophyllien.', 'seconde-svt-2', 'seconde-svt-2-s2', 6),
('seconde-svt-2-s2-l3', 'Mettre en évidence l''amidon', 'Réaliser l''expérience de mise en évidence de l''amidon dans une feuille pour révéler un produit de la photosynthèse.', 'seconde-svt-2', 'seconde-svt-2-s2', 7),
('seconde-svt-2-s2-l4', 'Chloroplaste et facteurs de la photosynthèse', 'Schématiser l''ultrastructure du chloroplaste et conclure sur les facteurs indispensables : chlorophylle, lumière, CO2, température.', 'seconde-svt-2', 'seconde-svt-2-s2', 8),
('seconde-svt-2-s2-l5', 'Le mécanisme de la photosynthèse', 'Expliquer la phase claire (photolyse de l''eau), la phase sombre (réduction du CO2) et écrire le bilan des réactions.', 'seconde-svt-2', 'seconde-svt-2-s2', 9),
('seconde-svt-2-s2-l6', 'Importance de la photosynthèse', 'Illustrer son rôle : reboisement, production de dioxygène, production alimentaire, pharmaceutique et de biopesticides.', 'seconde-svt-2', 'seconde-svt-2-s2', 10),
('seconde-c-svt-1-s1-l1', 'Le matériel de la sortie écologique', 'Utiliser sur le terrain le matériel nécessaire à l''étude des êtres vivants au cours d''une sortie écologique.', 'seconde-c-svt-1', 'seconde-c-svt-1-s1', 1),
('seconde-c-svt-1-s1-l2', 'Identifier les êtres vivants dans leurs milieux', 'Reconnaître animaux et végétaux dans le sol, le sous-sol, l''eau et l''air, avec des exemples togolais.', 'seconde-c-svt-1', 'seconde-c-svt-1-s1', 2),
('seconde-c-svt-1-s1-l3', 'Notions fondamentales d''écologie', 'Définir écologie, biotope, biocénose, écosystème, biomasse et environnement à partir des observations.', 'seconde-c-svt-1', 'seconde-c-svt-1-s1', 3),
('seconde-c-svt-1-s1-l4', 'Les zones écofloristiques du Togo', 'Localiser les principales zones abritant les écosystèmes au Togo : mangrove, savane, forêt, milieux aquatiques.', 'seconde-c-svt-1', 'seconde-c-svt-1-s1', 4),
('seconde-c-svt-1-s1-l5', 'Chaînes alimentaires et réseaux trophiques', 'Construire une chaîne alimentaire, repérer maillons et réseaux, expliquer les transferts de matière et d''énergie.', 'seconde-c-svt-1', 'seconde-c-svt-1-s1', 5),
('seconde-c-svt-1-s1-l6', 'Relations entre êtres vivants et interdépendance', 'Comparer relations intraspécifiques et interspécifiques, effet de groupe et effet de masse, et l''interdépendance.', 'seconde-c-svt-1', 'seconde-c-svt-1-s1', 6),
('seconde-c-svt-1-s2-l1', 'Les grands problèmes environnementaux', 'Identifier pollutions, déforestation, érosion côtière, perte de biodiversité, surpâturage, feux de brousse et braconnage.', 'seconde-c-svt-1', 'seconde-c-svt-1-s2', 7),
('seconde-c-svt-1-s2-l2', 'Effet de serre et réchauffement de la planète', 'Expliquer le mécanisme de l''effet de serre, les gaz responsables et la destruction de la couche d''ozone.', 'seconde-c-svt-1', 'seconde-c-svt-1-s2', 8),
('seconde-c-svt-1-s2-l3', 'Conséquences sur les écosystèmes', 'Déduire les conséquences des changements climatiques, des pollutions et de la disparition des espèces.', 'seconde-c-svt-1', 'seconde-c-svt-1-s2', 9),
('seconde-c-svt-1-s2-l4', 'Mesures de protection de l''environnement', 'Proposer reboisement, pare-feux, agroforesterie, recyclage et gestion durable des ressources naturelles.', 'seconde-c-svt-1', 'seconde-c-svt-1-s2', 10),
('seconde-c-svt-1-s2-l5', 'Produire des affiches de sensibilisation', 'Réaliser des affiches sensibilisant ses pairs au maintien de l''équilibre de la nature.', 'seconde-c-svt-1', 'seconde-c-svt-1-s2', 11),
('seconde-c-svt-2-s1-l1', 'Germination et croissance d''une plante verte', 'Décrire les étapes de développement : germination hétérotrophe puis croissance autotrophe.', 'seconde-c-svt-2', 'seconde-c-svt-2-s1', 1),
('seconde-c-svt-2-s1-l2', 'Rôle des sels minéraux N, P, K', 'Déterminer le rôle de chaque sel minéral et la notion de concentration optimale pour la croissance.', 'seconde-c-svt-2', 'seconde-c-svt-2-s1', 2),
('seconde-c-svt-2-s1-l3', 'Applications de la nutrition minérale', 'Déduire les applications : préparation d''engrais, culture sous serre, culture sans sol et aquaculture.', 'seconde-c-svt-2', 'seconde-c-svt-2-s1', 3),
('seconde-c-svt-2-s1-l4', 'Réaliser des cultures de légumes', 'Réaliser des cultures de tomates, haricot vert et fleurs dans le cadre d''espaces verts.', 'seconde-c-svt-2', 'seconde-c-svt-2-s1', 4),
('seconde-c-svt-2-s2-l1', 'Les échanges gazeux chlorophylliens', 'Mettre en évidence et analyser les échanges gazeux chlorophylliens à la lumière et à l''obscurité.', 'seconde-c-svt-2', 'seconde-c-svt-2-s2', 5),
('seconde-c-svt-2-s2-l2', 'Intensité et quotient d''assimilation chlorophylliens', 'Calculer l''intensité d''assimilation chlorophyllienne et le quotient d''assimilation chlorophyllien.', 'seconde-c-svt-2', 'seconde-c-svt-2-s2', 6),
('seconde-c-svt-2-s2-l3', 'Mise en évidence de l''amidon et facteurs', 'Révéler l''amidon dans une feuille et conclure sur chlorophylle, lumière, dioxyde de carbone et température.', 'seconde-c-svt-2', 'seconde-c-svt-2-s2', 7),
('seconde-c-svt-2-s2-l4', 'Chloroplaste et pigments chlorophylliens', 'Schématiser l''ultrastructure du chloroplaste et séparer les pigments foliaires par chromatographie.', 'seconde-c-svt-2', 'seconde-c-svt-2-s2', 8),
('seconde-c-svt-2-s2-l5', 'Mécanisme de la photosynthèse', 'Expliquer la phase claire, la phase sombre et écrire le bilan des réactions de la photosynthèse.', 'seconde-c-svt-2', 'seconde-c-svt-2-s2', 9),
('seconde-c-svt-2-s2-l6', 'Importance de la photosynthèse', 'Illustrer son rôle : reboisement, production alimentaire, pharmaceutique et biopesticides.', 'seconde-c-svt-2', 'seconde-c-svt-2-s2', 10),
('seconde-c-svt-3-s1-l1', 'Matériel et étude d''un sol sur le terrain', 'Utiliser les outils appropriés pour l''étude d''un sol au cours d''une sortie et prélever des échantillons.', 'seconde-c-svt-3', 'seconde-c-svt-3-s1', 1),
('seconde-c-svt-3-s1-l2', 'Types de sols et leurs caractéristiques', 'Identifier sableux, argileux, ferrugineux, ferralitiques et leurs caractéristiques : perméabilité, texture, pH.', 'seconde-c-svt-3', 'seconde-c-svt-3-s1', 2),
('seconde-c-svt-3-s1-l3', 'Répartition des sols au Togo', 'Identifier les différents types de sols du Togo à l''aide d''une carte simplifiée de leur répartition.', 'seconde-c-svt-3', 'seconde-c-svt-3-s1', 3),
('seconde-c-svt-3-s1-l4', 'Formation d''un sol', 'Expliquer la formation : altération de la roche mère et accumulation des débris végétaux et minéraux.', 'seconde-c-svt-3', 'seconde-c-svt-3-s1', 4),
('seconde-c-svt-3-s1-l5', 'Dégradation des sols', 'Décrire la dégradation sous les facteurs naturels et anthropiques : érosion, lessivage, acidification.', 'seconde-c-svt-3', 'seconde-c-svt-3-s1', 5),
('seconde-c-svt-3-s1-l6', 'Protection et reconstitution des sols', 'Décrire les techniques : reboisement, culture en terrasse et compostage.', 'seconde-c-svt-3', 'seconde-c-svt-3-s1', 6),
