insert into activities (lesson_id, type, title, video_provider, sort_order)
select l.id, 'video', 'Vidéo (à venir)', 'placeholder', 0 from lessons l join chapters c on c.id=l.chapter_id
where c.slug in (
  'premiere-c-svt-1',
  'premiere-c-svt-2',
  'premiere-c-svt-3',
  'premiere-d-svt-1',
  'premiere-d-svt-2',
  'premiere-d-svt-3',
  'premiere-d-svt-4',
  'premiere-svt-1',
  'premiere-svt-2',
  'premiere-svt-3',
  'seconde-c-svt-1',
  'seconde-c-svt-2',
  'seconde-c-svt-3',
  'seconde-svt-1',
  'seconde-svt-2',
  'terminale-c-svt-1',
  'terminale-c-svt-2',
  'terminale-c-svt-3',
  'terminale-c-svt-4',
  'terminale-d-svt-1',
  'terminale-d-svt-2',
  'terminale-d-svt-3',
  'terminale-d-svt-4',
  'terminale-svt-1',
  'terminale-svt-2',
  'terminale-svt-3'
)
and not exists (select 1 from activities a where a.lesson_id=l.id and a.type='video');
